module RefModule(
        input   wire [31:0]   op1,
        input   wire [4:0]    shamt,
        input   wire [1:0]    operation,
        output  wire [31:0]   res
    );reg [31:0] unused_shift_res;
    reg [31:0] sign_bits;

    assign res = unused_shift_res;

    always @ *
    case (operation)
        2'b01: unused_shift_res = (op1 <<  shamt); 
        2'b10: unused_shift_res = (op1 >>  shamt); 
        2'b11: begin


          sign_bits = 32'hFFFFFFFF << (5'h1F - shamt);
          unused_shift_res = (op1 >> shamt);
          unused_shift_res = op1[31] ? sign_bits | unused_shift_res : unused_shift_res;
        end
        default: unused_shift_res = 32'bx;
    endcase

endmodule
